PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?partner(SAMPLE(?name) AS ?name) WHERE {
  VALUES ?sister {
    wd:Q186304 wd:Q575689 wd:Q231270
  }
  {
    ?sister wdt:P451 ?partner
  } UNION {
    ?sister wdt:P26 ?partner
  }
  ?partner wdt:P31 wd:Q5 .
  OPTIONAL {
    ?partner rdfs:label ?name .
    FILTER(LANG(?name) = 'en')
  }
}
GROUP BY ?partner
